    TextDaemon daemon = new TextDaemon(Path.of("build/plugins/customer-default.jar"), 4);
    daemon.reload(1);
    List<ProcessingResult> firstResults = daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
    List<ProcessingResult> finalResults = firstResults;
    for (int current = 2; current <= 4; current++) {
        daemon.reload(current);
        finalResults = daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
    }
    boolean beforeClose = daemon.isBalanced();
    String first = firstResults.get(0).output();
    String last = finalResults.get(0).output();
    daemon.close();
    for (int i = 0; i < 3; i++) { System.gc(); Thread.sleep(50); }
    return new S(bean.getUnloadedClassCount() - unloadedBefore, beforeClose, daemon.isBalanced());
}
System.out.println(run());
