+import io.harbor.textd.core.TextDaemon;
+
+import java.lang.management.ClassLoadingMXBean;
+import java.lang.management.ManagementFactory;
+import java.lang.ref.WeakReference;
+import java.lang.reflect.Field;
+import java.nio.file.Path;
+import java.util.List;
+import java.util.concurrent.atomic.AtomicReference;
+
+public final class DebugProbe {
+    private DebugProbe() {
+    }
+
+    public static void main(String[] args) throws Exception {
+        ClassLoadingMXBean bean = ManagementFactory.getClassLoadingMXBean();
+        long unloadedBefore = bean.getUnloadedClassCount();
+
+        Snapshot snapshot = runSession();
+        for (int i = 0; i < 40; i++) {
+            System.gc();
+            Thread.sleep(50);
+        }
+
+        System.out.println("loader-alive=" + (snapshot.loader().get() != null));
+        System.out.println("frame-alive=" + (snapshot.frame().get() != null));
+        System.out.println("generation-alive=" + (snapshot.generation().get() != null));
+        System.out.println("unloaded=" + (bean.getUnloadedClassCount() - unloadedBefore));
+    }
+
+    private static Snapshot runSession() throws Exception {
+        TextDaemon daemon = new TextDaemon(Path.of("build/plugins/customer-default.jar"), 4);
+        daemon.reload(1);
+        daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
+        for (int current = 2; current <= 4; current++) {
+            daemon.reload(current);
+            daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
+        }
+
+        Snapshot snapshot = captureSnapshot(daemon);
+        daemon.close();
+        return snapshot;
+    }
+
+    private static Snapshot captureSnapshot(TextDaemon daemon) throws Exception {
+        Field revisionsField = TextDaemon.class.getDeclaredField("revisions");
+        revisionsField.setAccessible(true);
+        Object revisions = revisionsField.get(daemon);
+
+        Field currentField = revisions.getClass().getDeclaredField("current");
+        currentField.setAccessible(true);
+        AtomicReference<?> current = (AtomicReference<?>) currentField.get(revisions);
+        Object frame = current.get();
+
+        Field generationField = frame.getClass().getDeclaredField("loadedGeneration");
+        generationField.setAccessible(true);
+        Object generation = generationField.get(frame);
+
+        Field classLoaderField = generation.getClass().getDeclaredField("classLoader");
+        classLoaderField.setAccessible(true);
+        return new Snapshot(
+            new WeakReference<>(frame),
+            new WeakReference<>(generation),
+            new WeakReference<>((ClassLoader) classLoaderField.get(generation))
+        );
+    }
+
+    private record Snapshot(
+        WeakReference<Object> frame,
+        WeakReference<Object> generation,
+        WeakReference<ClassLoader> loader
+    ) {
+    }
+}
